import json
from datetime import datetime

rows = var_call_M5nVvlAKAdW1hjwZ6j4ePFXT

fmt = '%Y-%m-%dT%H:%M:%S.000+0000'
handle_times = {}
case_counts = {}

for r in rows:
    created = datetime.strptime(r['createddate'], fmt)
    closed = datetime.strptime(r['closeddate'], fmt)
    minutes = (closed - created).total_seconds() / 60.0
    aid = r['agent_id']
    handle_times.setdefault(aid, []).append(minutes)
    case_counts[aid] = case_counts.get(aid, 0) + 1

avg_times = {}
for aid, times in handle_times.items():
    if case_counts.get(aid, 0) > 1:
        avg_times[aid] = sum(times) / len(times)

if not avg_times:
    result = None
else:
    result = min(avg_times, key=avg_times.get)

result_json = json.dumps(result)
print("__RESULT__:")
print(result_json)
